INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-d0d1b9a2-moex-00275', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「不要寄望法律有那麼強大的理性功能，意思也就是不要寄望法律對公平正義都會有一個清 楚的輪廓。不過，這種對法律謙虛的期待或許現實上是不切實際的，因為法院案源的急速膨 脹突顯兩件事情，一個是人對彼此包容性的減低，另外一個是人對法律理性的迷信。但無論 如何，如果不是人們相互之間多一些包容的意願，即使法律設計出什麼制度，問題終究難以 根本解決。」 根據上文，下列敘述符合文意的是：', '["法律制度最重要的特質是強大的理性功能", "人民對法律謙虛的期待造成法院案源膨脹", "法律制度具備一定的公平正義但有其限度", "人們相互包容是法律問題的根本解決之道 我們應該修改法律直到它能主持人間正義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00276', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「想化危機為轉機，恢復企業停滯的業務，必須在一開始採取正確的行動。縱使在最破碎的 公司裡，十件事中仍有八件事是由優秀人才所完成。因此，增加獲利的有效方法之一，就是 表揚出色人員。這樣，對身處公司復原期的層峰主管而言，可以建立領導信心；對員工而言， 則可以感受到上級的信任，並且知道該朝什麼方向努力。」 根據上文，下列敘述符合文意的是：', '["受復原期影響，優秀人才發揮有限", "主管自我表彰，可為員工樹立標竿", "善用獎勵策略，能助員工確立目標", "鼓舞優秀員工，可以改善企業文化 福利措施越多，越能給予員工動力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00277', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「某某牌電動腳底按摩泡腳機使用注意事項：(1)飯後一小時內請避免使用本產品，以避免消 化不良。(2)懷孕婦女請避免使用。(3)如在高血壓、心臟病等發作期，請暫停使用以避免發生 意外。(4)一次使用以30分鐘為原則，請勿連續使用過長的時間。(5)對於一些老人及小孩溫 度感覺遲緩者，必須由健康反應正常的家人陪同使用，避免過度使用傷害皮膚。」 根據上文，下列敘述適當的是：', '["一般人飯後一小時即可使用該產品", "產婦坐月子時應該避免使用該產品", "有高血壓但未發作時可使用該產品", "連續使用40分鐘會造成該產品故障 連續過度使用該產品仍會傷害皮膚"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00278', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「我第一遭清楚看到這群水鳥的眼神。每一隻濱鷸的眼神，充滿著陌生、不馴與無可言喻的 神祕。對於賞鳥人而言，眼神是鳥最生動、也最無法觀察的地方。拍攝野鳥的人也以抓住牠 的眼神為第一要素。這是我第一次強烈感受牠們身上散發出的光澤，從來沒有見過如此純然 灰褐的色彩。這種平實的灰褐一直是牠們忍受酷寒，免受敵害，保護牠們從北方千里迢迢抵 臨的顏色。灰褐代表了安全，也象徵著遷徙、旅行、流浪冒險的顏色。這種顏色不是底片或 是顏料所能拍攝、渲染得體，完滿表達出來的。」 下列敘述，符合上文觀點的是：', '["濱鷸平實的顏色，同時代表流浪冒險與安全", "找到最近的觀察距離，是拍攝野鳥的第一要素", "對賞鳥人而言，濱鷸最大的特色是身上散發出的光澤", "對作者而言，觀察濱鷸的眼神比身上的光澤來得重要 灰褐羽毛象徵濱鷸的生命經驗，這是相機無法傳達的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00279', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「古代希臘哲學家亞里斯多德說：『快樂就是生命的意義和目的，也是人類生存的總目標』； 還有一位奧妙的悲觀主義者，德國哲學家叔本華的一句智慧之言：『快樂乃是健康所開放的 花朵，而健康則從勤勞、節慾、衛生產生。』一點也不假，健康必須力求身心兩健，保養生 理的健康，必也同時保持心理的健全，才能整合身心兩者的愉快，延年益壽。」 根據上文，下列敘述適當的是：', '["生命的意義和目的，在於實踐自己的願望", "勤奮地工作，可以彰顯生命的意義和目的", "做好環境清潔，是讓自己獲得快樂的捷徑", "同時保持生理和心理健康，可以延年益壽 人生最大的快樂，來自於擁有樂觀與智慧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00280', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「『核心素養』是社會群體成員共有的知識、能力與態度，是全方位的素養；『專門素養』 是特定行業人員所具備的特定行業或專門職業的專門素養之知識、能力與態度。『核心素養』 主要目的是強調社會功能，以建立功能健全的社會；『專門素養』主要目的是強調個人具備 特定行業所需的素養，以加入特定專門職業團體，以協助個人獲得成功的生活。」 根據上文，下列選項何者對素養類別的判斷正確？', '["核心素養：開車時願意禮讓行人", "專門素養：能與他人溝通並互動", "核心素養：可以自行研發新產品", "專門素養：能成功行銷工商百貨 核心素養：開發水產養殖新方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00281', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年5月1日支付一年保險費，並將其全額記為保險費。X1年12月31日有關此保險費之調 整分錄為借記預付保險費$2,600。試問X1年5月1日所支付之保險費金額為何？', '["$3,900", "$5,200", "$5,850", "$7,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00282', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司發行並流通在外面額$10的普通股股本$30,000,000，以及面額$25、股利率5%的非累積、非參加特 別股股本$15,000,000。X1年甲公司決議不發放股利，但X2年決議發放$3,500,000的股利，則X2年特別 股股東可以領取多少股利金額？', '["$750,000", "$1,500,000", "$1,750,000", "$3,500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00283', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '公司帳上銀行存款餘額較銀行對帳單銀行存款餘額為低，下列何者可能是造成此一差異的原因？', '["公司對開立給供應商支付貨款之即期支票於帳簿上少計", "公司原存入之支票，因存款不足被退票", "公司有未兌現支票", "公司有在途存款"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00284', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丁公司編製X3年5月份之銀行調節表，辨認出$30,000在途存款，有關該在途存款之會計處理，下列何 者正確？', '["借：現金$30,000", "借：應收票據$30,000", "貸：應收帳款$30,000", "不作分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "661f3568be1b", "answer_pdf_sha1": "4f7f06df392a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
